from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

# Redis connection settings
redis_config = {
    'host': 'localhost',
    'port': 6379,
    'db': 0
}

@app.route('/execute', methods=['POST'])
def execute_redis_command():
    try:
        # Get the command from request arguments
        command = request.args.get('command')
        
        if not command:
            return jsonify({'error': 'Missing required parameter: command'}), 400
        
        # Execute Redis command using redis.execute_command()
        with redis.Redis(**redis_config) as r:
            result = r.execute_command(command)
            
            # Return the result of the executed command
            return jsonify(result), 200
    
    except Exception as e:
        # Handle any exceptions that occur during execution
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)